/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements NotificationAdapter for the 'sms' channel with:
 * - Phone number validation and normalization
 * - Message formatting (subject + body, truncated to SMS limits)
 * - Configurable SMS transport (defaults to in-memory for testing)
 *
 * Architecture constraint: all notification delivery goes through
 * adapters implementing NotificationAdapter, registered via
 * NotificationService.registerAdapter().
 *
 * NOTE: User preferences (src/models/user-preferences.ts) currently
 * assume email-only channels. They need to be updated to support
 * per-channel preferences (e.g., smsEnabled, smsSubscribedCategories).
 * See decision records for details.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
  notificationId: string;
}

export interface SmsConfig {
  /** Maximum message length. SMS standard is 160 chars. */
  maxLength?: number;
  /** Optional transport function for sending SMS. Defaults to in-memory storage. */
  transport?: SmsTransport;
}

/**
 * Pluggable SMS transport. Return true for success, throw for failure.
 * In production, this would wrap Twilio, AWS SNS, etc.
 */
export type SmsTransport = (message: SmsMessage) => Promise<boolean>;

/** SMS character limit. */
const DEFAULT_MAX_LENGTH = 160;

/**
 * Phone number regex: must start with + followed by 7-15 digits.
 * Matches E.164 format (e.g., +14155551234).
 */
const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private config: SmsConfig;

  constructor(config?: SmsConfig) {
    this.config = config ?? {};
  }

  /**
   * Send an SMS notification.
   * Validates recipient phone number, formats message, and delivers via transport.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedPhone = this.resolveRecipient(payload.recipient);

      if (!resolvedPhone) {
        this.logger.warn(`Invalid phone number: ${payload.recipient}`);
        return {
          success: false,
          channel: this.channel,
          error: `Invalid phone number: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      const body = this.formatMessage(payload);

      const message: SmsMessage = {
        to: resolvedPhone,
        body,
        sentAt: new Date(),
        notificationId: payload.id,
      };

      if (this.config.transport) {
        await this.config.transport(message);
      }

      this.sentMessages.push(message);

      this.logger.info(`SMS sent to ${resolvedPhone}: ${body.substring(0, 40)}...`);

      return {
        success: true,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        channel: this.channel,
        error: `SMS delivery failed: ${errorMessage}`,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Validate and normalize a phone number.
   * Strips spaces and dashes, then checks E.164 format.
   * Returns the normalized number, or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const cleaned = recipient.trim().replace(/[\s\-()]/g, '');

    if (!cleaned) {
      return null;
    }

    if (!PHONE_REGEX.test(cleaned)) {
      return null;
    }

    return cleaned;
  }

  /**
   * Format notification payload into an SMS message body.
   * Combines subject and body, truncated to max length.
   */
  formatMessage(payload: NotificationPayload): string {
    const maxLength = this.config.maxLength ?? DEFAULT_MAX_LENGTH;
    const full = `${payload.subject}: ${payload.body}`;

    if (full.length <= maxLength) {
      return full;
    }

    return full.substring(0, maxLength - 3) + '...';
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'sms',
    recipient: '+14155551234',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    createdAt: new Date(),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('channel', () => {
    it('should report sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(adapter.resolveRecipient('+14155551234')).toBe('+14155551234');
      expect(adapter.resolveRecipient('+442071234567')).toBe('+442071234567');
    });

    it('should strip spaces, dashes, and parentheses', () => {
      expect(adapter.resolveRecipient('+1 (415) 555-1234')).toBe('+14155551234');
      expect(adapter.resolveRecipient('  +1-415-555-1234  ')).toBe('+14155551234');
    });

    it('should reject invalid phone numbers', () => {
      expect(adapter.resolveRecipient('')).toBeNull();
      expect(adapter.resolveRecipient('not-a-phone')).toBeNull();
      expect(adapter.resolveRecipient('4155551234')).toBeNull();
      expect(adapter.resolveRecipient('+0123456789')).toBeNull();
      expect(adapter.resolveRecipient('+1')).toBeNull();
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body', () => {
      const payload = makePayload();
      const message = adapter.formatMessage(payload);

      expect(message).toBe('Order Confirmation: Your order has been placed.');
    });

    it('should truncate long messages to 160 chars', () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ body: longBody });
      const message = adapter.formatMessage(payload);

      expect(message.length).toBe(160);
      expect(message.endsWith('...')).toBe(true);
    });

    it('should not truncate messages within limit', () => {
      const payload = makePayload({ subject: 'Hi', body: 'Short' });
      const message = adapter.formatMessage(payload);

      expect(message).toBe('Hi: Short');
    });

    it('should respect custom max length', () => {
      const customAdapter = new SmsAdapter({ maxLength: 50 });
      const longBody = 'A'.repeat(100);
      const payload = makePayload({ body: longBody });
      const message = customAdapter.formatMessage(payload);

      expect(message.length).toBe(50);
      expect(message.endsWith('...')).toBe(true);
    });
  });

  describe('send', () => {
    it('should send SMS successfully for valid phone number', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();
    });

    it('should store sent message with correct fields', async () => {
      await adapter.send(makePayload());

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+14155551234');
      expect(messages[0]?.body).toContain('Order Confirmation');
      expect(messages[0]?.notificationId).toBe('notif-0001');
      expect(messages[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should return failure for invalid phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-phone' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return failure when transport throws', async () => {
      const failingAdapter = new SmsAdapter({
        transport: async () => { throw new Error('SMS gateway unavailable'); },
      });

      const result = await failingAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMS gateway unavailable');
    });

    it('should call custom transport when provided', async () => {
      const transport = vi.fn().mockResolvedValue(true);
      const customAdapter = new SmsAdapter({ transport });

      await customAdapter.send(makePayload());

      expect(transport).toHaveBeenCalledOnce();
      const message = transport.mock.calls[0]![0];
      expect(message.to).toBe('+14155551234');
      expect(message.body).toContain('Order Confirmation');
    });

    it('should normalize recipient phone number', async () => {
      await adapter.send(makePayload({ recipient: '+1 (415) 555-1234' }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+14155551234');
    });
  });

  describe('getSentMessages and clearSentMessages', () => {
    it('should return copies of sent messages', async () => {
      await adapter.send(makePayload());

      const messages1 = adapter.getSentMessages();
      const messages2 = adapter.getSentMessages();
      expect(messages1).not.toBe(messages2);
      expect(messages1).toEqual(messages2);
    });

    it('should clear sent message history', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
});

